// GitHub branch protection settings (via API or UI)
// Apply to: main, release/*, and any branch pattern that deploys to production

{
  "required_status_checks": {
    "strict": true,
    "contexts": [
      "static-checks",          // lint, type check, schema validation
      "unit-tests",             // prompt assembly, tool schema unit tests
      "eval-suite",             // LLM eval gate — ≥90% pass rate
      "integration-tests"       // end-to-end tool call verification
    ]
  },
  "enforce_admins": true,        // applies to repo admins too — no bypass
  "required_pull_request_reviews": {
    "dismiss_stale_reviews": true,  // new commits void existing approvals
    "require_code_owner_reviews": true,
    "required_approving_review_count": 1
  },
  "restrictions": null,          // any team member can push to a feature branch
  "allow_force_pushes": false,
  "allow_deletions": false,
  "required_conversation_resolution": true  // all review comments must be resolved
}
